let runFilter = '{TestRunId}';
let priceIn = todouble('{PriceInputPer1k}');
let priceOut = todouble('{PriceOutputPer1k}');
let prompt = toscalar(customMetrics | where name == 'Prompt Tokens' | extend t = tostring(customDimensions['Test Run ID']) | where (runFilter == '' or t == runFilter) | summarize sum(valueSum));
let completion = toscalar(customMetrics | where name == 'Completion Tokens' | extend t = tostring(customDimensions['Test Run ID']) | where (runFilter == '' or t == runFilter) | summarize sum(valueSum));
print Metric = 'Estimated cost (USD)', Value = round((coalesce(prompt,0.0)/1000.0)*priceIn + (coalesce(completion,0.0)/1000.0)*priceOut, 4)

let runFilter = '{TestRunId}';
let priceIn = todouble('{PriceInputPer1k}');
let priceOut = todouble('{PriceOutputPer1k}');
let prompt = customMetrics | where name == 'Prompt Tokens' | extend Product = tostring(customDimensions['Product']), t = tostring(customDimensions['Test Run ID']) | where (runFilter == '' or t == runFilter) | summarize p = sum(valueSum) by Product;
let completion = customMetrics | where name == 'Completion Tokens' | extend Product = tostring(customDimensions['Product']), t = tostring(customDimensions['Test Run ID']) | where (runFilter == '' or t == runFilter) | summarize c = sum(valueSum) by Product;
prompt
| join kind=fullouter completion on Product
| extend Product = coalesce(Product, Product1)
| extend CostUSD = round((coalesce(p,0.0)/1000.0)*priceIn + (coalesce(c,0.0)/1000.0)*priceOut, 4)
| project Product, ['Prompt tokens'] = p, ['Completion tokens'] = c, CostUSD
| order by CostUSD desc
